conn = sqlite3.connect("data/sai_enterprises.db")
conn.execute("DELETE FROM products")
for p in products:
    conn.execute("""INSERT INTO products (sku,store_name,platform,category,cost,selling_price,image_url,status,rto_per,ret_per,inventory)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?)""",
        (p["sku"],p["store_name"],p["platform"],p["category"],p["cost"],p["selling_price"],
         p["image_url"],p["status"],p["rto_per"],p["ret_per"],p["inventory"]))
conn.commit()
print("Products imported:", conn.execute("SELECT COUNT(*) FROM products").fetchone()[0])
conn.close()
